export type Runtime = "iframe-html" | "esm-module";
export type Capability = "score" | "progress" | "levels" | "hints" | "save-progress" | "audio" | "leaderboard" | "telemetry";
export interface GameManifest {
    id: string;
    title: string;
    version: string;
    runtime: Runtime;
    entryUrl: string;
    iconUrl?: string;
    capabilities?: Capability[];
    minHubVersion?: string;
    rolloutPercentage?: number;
    disabled?: boolean;
    metadata?: Record<string, any>;
}
export interface GameRuntimeConfig {
    runtime: Runtime;
    locale: string;
    difficulty: number;
    seed?: number;
    player: {
        userId: string;
        profile?: Record<string, unknown>;
    };
    hubApi: GameBridgeApi;
}
export interface SaveState {
    version: number;
    ts: number;
    payload: Record<string, unknown>;
}
export interface TelemetryEvent {
    ts: number;
    type: string;
    data?: Record<string, unknown>;
    sessionId?: string;
}
export interface GameBridgeApi {
    postEvent(e: TelemetryEvent): void;
    save(state: SaveState): Promise<void>;
    load(): Promise<SaveState | null>;
    getSetting<T = unknown>(key: string): Promise<T | null>;
    request(name: string, payload?: unknown): Promise<unknown>;
}
export interface IrukaGame {
    onInit(cfg: GameRuntimeConfig): Promise<void> | void;
    onStart(): Promise<void> | void;
    onPause?(): void;
    onResume?(): void;
    onDispose?(): void;
}
